VALUES
  ('aboriginal-f0899a01-moex-00197', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-112-e2754278', 'sub-aboriginal-f0899a01-05', NULL, 'single_choice', '甲因看見乙殺丙，分別經檢察官及法院傳喚到庭作證，下列敘述何者正確？', '["甲於檢察官偵查中作證稱乙不在案發現場，未經具結，於法院審判中具結作證稱確實看見乙殺人， 不成立偽證罪", "甲於檢察官偵查中未經具結作證稱乙不在案發現場，於法院審判中具結作證稱確實看見乙殺人，仍 成立偽證罪", "甲於檢察官偵查中具結作證稱確實看見乙殺丙，於法院審判中具結作證稱乙應該不在案發現場，是 記錯了，並不成立偽證罪", "甲於檢察官偵查中未經具結，作證稱確實看見乙殺丙，於法院審判中具結作證稱乙應該不在案發現 場，是記錯了，並不成立偽證罪"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:32+00:00", "source_pdf_sha1": "82bf4eaffd97", "answer_pdf_sha1": "928b35146456", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "608", "s": "0811", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00198', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-112-e2754278', 'sub-aboriginal-f0899a01-05', NULL, 'single_choice', '有關刑法第185條之3第1項不能安全駕駛罪，下列敘述何者錯誤？', '["本罪係實害犯", "汽車駕駛人吐氣所含酒精濃度達每公升0.25毫克，即成立本罪", "電動自行車亦屬動力交通工具", "服用毒品致不能安全駕駛，亦成立本罪"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:32+00:00", "source_pdf_sha1": "82bf4eaffd97", "answer_pdf_sha1": "928b35146456", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "608", "s": "0811", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00199', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-112-e2754278', 'sub-aboriginal-f0899a01-05', NULL, 'single_choice', '有關刑法第190條之1環境污染罪，下列敘述何者錯誤？', '["污染的對象包括空氣、土壤、河川或其他水體", "行為主體包括廠商或事業場所之負責人、受僱人", "污染須致生公共危險始成立犯罪", "本罪亦處罰過失犯"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:32+00:00", "source_pdf_sha1": "82bf4eaffd97", "answer_pdf_sha1": "928b35146456", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "608", "s": "0811", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00200', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-112-e2754278', 'sub-aboriginal-f0899a01-05', NULL, 'single_choice', '有關刑法第13章偽造有價證券罪的敘述，下列何者正確？', '["意圖供行使偽造悠遊卡，並不會構成犯罪", "意圖供行使變造高鐵車票把座位從經濟艙變成商務艙，只要補差價並不構成犯罪", "意圖供行使偽造振興五倍券，不成立僞造有價證券罪", "偽造、變造之有價證券、郵票、印花稅票，不問屬於犯人與否，均需要宣告沒收"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:32+00:00", "source_pdf_sha1": "82bf4eaffd97", "answer_pdf_sha1": "928b35146456", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "608", "s": "0811", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00201', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-112-e2754278', 'sub-aboriginal-f0899a01-05', NULL, 'single_choice', '關於刑法第210條之偽造私文書罪，下列敘述何者正確？', '["文書係指任何形諸於文字之意思表達", "偽造係指變更真正文書之部分內容", "本罪僅保護文書內容之真實性", "偽造行為係指未得本人授權之製作文書行為"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:32+00:00", "source_pdf_sha1": "82bf4eaffd97", "answer_pdf_sha1": "928b35146456", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "608", "s": "0811", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00202', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-112-e2754278', 'sub-aboriginal-f0899a01-05', NULL, 'single_choice', '甲於公園內見年僅5歲之乙女獨自一人玩耍，竟基於對乙性侵害之犯意，將乙強抱坐在其左腿上，乙 不願意，一直推開甲，卻因力量太小，終遭甲伸手入乙運動褲內，以右手手指插入乙之陰道得逞。依 實務見解，甲之行為應如何論罪？', '["刑法第228條利用權勢或機會性交罪", "刑法第222條加重強制性交罪", "刑法第225條乘機性交罪", "刑法第227條第1項對未滿14歲之女子為性交罪"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:32+00:00", "source_pdf_sha1": "82bf4eaffd97", "answer_pdf_sha1": "928b35146456", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "608", "s": "0811", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00203', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-112-e2754278', 'sub-aboriginal-f0899a01-05', NULL, 'single_choice', '在一般超市販售下列何種物品，不成立刑法第235條散布播送販賣猥褻物品罪？', '["有包裝封膜之內含人獸性交圖片之雜誌", "有包裝封膜之內含兒童性侵害圖片之雜誌", "有包裝封膜之內含女性上空裸照之雜誌", "有包裝封膜之內含暴力性虐待圖片之雜誌"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:32+00:00", "source_pdf_sha1": "82bf4eaffd97", "answer_pdf_sha1": "928b35146456", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "608", "s": "0811", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00204', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-112-e2754278', 'sub-aboriginal-f0899a01-05', NULL, 'single_choice', '對和誘及略誘之敘述，下列何者正確？', '["和略是遭到引誘的人數總合", "略誘是約略輕度的引誘", "略誘是以非和平之手段予以誘拐", "和誘與略誘都是違反被害人的意思"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:32+00:00", "source_pdf_sha1": "82bf4eaffd97", "answer_pdf_sha1": "928b35146456", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "608", "s": "0811", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00205', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-112-e2754278', 'sub-aboriginal-f0899a01-05', NULL, 'single_choice', '有關刑法殺人罪章之規定，下列敘述何者錯誤？', '["殺人罪之行為客體，限於出生後、死亡前之自然人", "殺害直系血親尊親屬者，依殺人罪加重其刑至二分之一", "刑法第274條生母殺嬰罪之行為客體，包括甫生產後之嬰兒", "計程車司機超速駕駛而過失致人於死者，成立業務過失致死罪"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:32+00:00", "source_pdf_sha1": "82bf4eaffd97", "answer_pdf_sha1": "928b35146456", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "608", "s": "0811", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00206', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-112-e2754278', 'sub-aboriginal-f0899a01-05', NULL, 'single_choice', '有關遺棄罪相關規定之說明，下列敘述何者正確？', '["阻斷無自救能力之人逃生之機會，屬不作為遺棄行為", "車禍重傷確定必將死亡之人，不屬本罪之無自救能力之人", "依實務見解，遺棄罪所謂之法令、契約所生的保護義務，不包含無因管理的情況", "甫出生3日之嬰兒，因可自行呼吸，不屬本罪之無自救能力之人"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:32+00:00", "source_pdf_sha1": "82bf4eaffd97", "answer_pdf_sha1": "928b35146456", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "608", "s": "0811", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL)
